+import type { Trait, TraitRecord } from '../trait/types';
+import type { World } from '../world';
+
+let aspectId = 0;
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Record<string, unknown>;
+};
+
+export type AspectRecord<T extends Aspect = Aspect> = T extends Aspect<infer Traits>
+    ? UnionToIntersection<TraitRecord<Traits[number]>>
+    : never;
+
+type UnionToIntersection<T> = (T extends unknown ? (value: T) => void : never) extends (
+    value: infer R
+) => void
+    ? R
+    : never;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!value && typeof value === 'object' && Array.isArray((value as Aspect).traits);
+}
+
+export function createAspect<const T extends readonly [Trait | Aspect, Trait | Aspect, ...(Trait | Aspect)[]]>(
+    ...constituents: T
+): Aspect {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const constituent of constituents) {
+        const nested = isAspect(constituent) ? constituent.traits : [constituent];
+        for (const trait of nested) {
+            if (isRelation(trait) || trait[$internal].relation) {
+                throw new Error('Koota: Relations cannot be constituents of an aspect.');
+            }
+            if (traits.includes(trait)) continue;
+            const traitSchema = trait.schema as Record<string, unknown>;
+            for (const field of Object.keys(traitSchema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Koota: Aspect constituents overlap on field "${field}".`);
+                }
+                fields.add(field);
+                schema[field] = traitSchema[field];
+            }
+            traits.push(trait);
+        }
+    }
+
+    return Object.freeze({ id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema) });
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const value: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(value, getTrait(world, entity, trait));
+    return value;
+}
+
+function valuesForTrait(trait: Trait, value: Record<string, unknown>) {
+    const result: Record<string, unknown> = {};
+    for (const field of Object.keys(trait.schema as Record<string, unknown>)) {
+        if (field in value) result[field] = value[field];
+    }
+    return result;
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown> = {}) {
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, valuesForTrait(trait, value)]);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown>) {
+    for (const trait of aspect.traits) setTrait(world, entity, trait, valuesForTrait(trait, value));
+}
